```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id and username (with length prefix)
        stream(packet_id, hexi::prefixed(username));

        // Write scores count first, then scores elements
        uint32_t scores_count = static_cast<uint32_t>(scores.size());
        stream << scores_count;
        stream << scores;

        // Write null-terminated metadata
        stream(hexi::null_terminated(metadata));
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create buffer and stream
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize the packet
    const_cast<NetworkPacket&>(packet).serialise(stream);

    return buffer;
}
```

