NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket packet;

    // Read the packet_id
    stream.get(packet.packet_id);

    // Read the username using the length prefix
    stream.get_prefixed(packet.username);

    // Read the score count
    uint32_t score_count;
    stream.get(score_count);

    // Use read_container to read the scores vector
    stream.read_container(packet.scores, score_count);

    // Read the metadata string as null-terminated
    stream.get_null_terminated(packet.metadata);

    // Skip any remaining padding bytes (if any)
    // Note: Only skip if there are remaining bytes
    if (stream.size() > 0) {
        stream.skip(stream.size());
    }

    return packet;
}

