    auto buffer = create_user_buffer(123456789, 25, "Alice");

    UserData user = deserialize_user_data(buffer);

    EXPECT_EQ(123456789, user.user_id);
    EXPECT_EQ(25, user.age);
    EXPECT_EQ("Alice", user.name);
}

