```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Calculate required space
    // header (4 bytes) + container size (4 bytes) + items (items.size() * 4 bytes)
    size_t required_space = sizeof(uint32_t) + sizeof(uint32_t) + items.size() * sizeof(uint32_t);

    // Check available space and reserve if needed
    if (buffer.capacity() < buffer.size() + required_space) {
        buffer.reserve(buffer.size() + required_space);
    }

    // Create buffer adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Get the write pointer (current position)
    auto write_pos = stream.tell();

    // Write header
    stream << header;

    // Write container data
    stream.write_container(items);

    // Return true if write was successful, false if insufficient space
    return stream.good();
}
```

