PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream from adaptor
    hexi::binary_stream stream(adaptor);

    // 1. Get the read pointer (buffer_adaptor pointer method)
    [[maybe_unused]] const auto* read_ptr = adaptor.read_ptr();

    // 2. Check available data (buffer_adaptor size checking method)
    [[maybe_unused]] const auto available = adaptor.read_size();

    // 3. Read header using binary_stream's zero-copy operations
    // The stream operations work directly on the underlying buffer without copying
    PacketHeader header;
    stream >> header.magic >> header.version >> header.flags;

    return header;
}
