#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator for uint64_t with specified element_count
    hexi::block_allocator<std::uint64_t, element_count> allocator;

    std::cout << "=== Demonstrating Block Allocator Free List Management ===" << std::endl;
    std::cout << "Initial state:" << std::endl;
    std::cout << "  Storage active count: " << allocator.storage_active_count << std::endl;
    std::cout << "  Total allocations: " << allocator.total_allocs << std::endl;
    std::cout << "  Total deallocations: " << allocator.total_deallocs << std::endl;

    // Allocate some blocks - internally uses pop() to remove from free list
    std::cout << "\nAllocating 5 blocks (internally calls pop())..." << std::endl;
    std::vector<std::uint64_t*> allocated_blocks;
    for (size_t i = 0; i < 5; ++i) {
        auto* block = allocator.allocate();
        *block = i * 100; // Write some data
        allocated_blocks.push_back(block);
    }

    std::cout << "After allocation:" << std::endl;
    std::cout << "  Storage active count: " << allocator.storage_active_count << std::endl;
    std::cout << "  Total allocations: " << allocator.total_allocs << std::endl;

    // Deallocate some blocks - internally uses push() to add back to free list
    std::cout << "\nDeallocating 3 blocks (internally calls push())..." << std::endl;
    for (size_t i = 0; i < 3; ++i) {
        allocator.deallocate(allocated_blocks[i]);
    }
    allocated_blocks.erase(allocated_blocks.begin(), allocated_blocks.begin() + 3);

    std::cout << "After deallocation:" << std::endl;
    std::cout << "  Storage active count: " << allocator.storage_active_count << std::endl;
    std::cout << "  Total deallocations: " << allocator.total_deallocs << std::endl;

    // Allocate again - reuses blocks from free list (pop())
    std::cout << "\nAllocating 2 more blocks (reuses from free list via pop())..." << std::endl;
    for (size_t i = 0; i < 2; ++i) {
        auto* block = allocator.allocate();
        *block = (i + 5) * 100;
        allocated_blocks.push_back(block);
    }

    std::cout << "After reallocation:" << std::endl;
    std::cout << "  Storage active count: " << allocator.storage_active_count << std::endl;
    std::cout << "  Total allocations: " << allocator.total_allocs << std::endl;

    // Clean up remaining allocations
    std::cout << "\nCleaning up remaining blocks..." << std::endl;
    for (auto* block : allocated_blocks) {
        allocator.deallocate(block);
    }

    std::cout << "\nFinal state:" << std::endl;
    std::cout << "  Storage active count: " << allocator.storage_active_count << std::endl;
    std::cout << "  Total allocations: " << allocator.total_allocs << std::endl;
    std::cout << "  Total deallocations: " << allocator.total_deallocs << std::endl;

    std::cout << "\n=== Free List Behavior Summary ===" << std::endl;
    std::cout << "- allocate() internally calls pop() to remove a block from the free list head" << std::endl;
    std::cout << "- deallocate() internally calls push() to add a block back to the free list head" << std::endl;
    std::cout << "- The free list operates as a LIFO (Last In, First Out) stack" << std::endl;
    std::cout << "- Deallocated blocks are reused on subsequent allocations" << std::endl;
}
