#include <gtest/gtest.h>
#include <hexi/pmc/stream_base.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>

// Include the implementation
#include "implementation.hpp"

// Helper: Create a mock buffer for testing
class MockBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;
public:
    MockBuffer() : data_(100) {}
    std::size_t size() const override { return data_.size(); }
    bool empty() const override { return data_.empty(); }
};

TEST(StreamBase, ClearStreamState) {
    MockBuffer buffer;
    hexi::pmc::stream_base stream(buffer);

    stream.set_error_state();
    EXPECT_EQ(hexi::stream_state::user_defined_err, stream.state());

    clear_stream_state(stream);

    EXPECT_EQ(hexi::stream_state::ok, stream.state());
}

TEST(StreamBase, SetStreamError) {
    MockBuffer buffer;
    hexi::pmc::stream_base stream(buffer);

    EXPECT_EQ(hexi::stream_state::ok, stream.state());

    set_stream_error(stream);

    EXPECT_EQ(hexi::stream_state::user_defined_err, stream.state());
}

TEST(StreamBase, CheckStreamState) {
    MockBuffer buffer;
    hexi::pmc::stream_base stream(buffer);

    auto state = check_stream_state(stream);
    EXPECT_EQ(hexi::stream_state::ok, state);

    set_stream_error(stream);
    state = check_stream_state(stream);
    EXPECT_EQ(hexi::stream_state::user_defined_err, state);

    clear_stream_state(stream);
    state = check_stream_state(stream);
    EXPECT_EQ(hexi::stream_state::ok, state);
}

