#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the count (size) of the container first
    uint32_t count = static_cast<uint32_t>(container.size());
    writer << count;

    // Write each element
    for (const auto& element : container) {
        writer << element;
    }
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the count first
    uint32_t count;
    reader >> count;

    // Create vector and reserve space for efficiency
    std::vector<uint32_t> container;
    container.reserve(count);

    // Read each element
    for (uint32_t i = 0; i < count; ++i) {
        uint32_t element;
        reader >> element;
        container.push_back(element);
    }

    return container;
}
```

## Explanation:

**`write_container_to_stream`:**
1. First writes the container size as a `uint32_t` count (prefixed count)
2. Then iterates through each element and writes it to the stream using the `<<` operator

**`read_container_from_stream`:**
1. First reads the count from the stream using the `>>` operator
2. Reserves space in the vector for efficiency (avoids multiple reallocations)
3. Reads each element one by one and adds it to the vector
4. Returns the populated vector

The implementation uses the standard stream operator pattern (`<<` for writing, `>>` for reading) which is the idiomatic approach for the Hexi library's binary stream classes.

