```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    if (buffer.empty()) {
        return nullptr;
    }
    return &buffer[0];
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    return BufferState{
        buffer.size(),
        get_read_pointer(buffer),
        buffer.empty()
    };
}
```

