#include "implementation.hpp"

TEST(Varint, EncodeDecodeSmall) {
    std::vector<std::byte> buffer(1000);
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    hexi::pmc::buffer& buf_ref = adaptor;
    hexi::pmc::binary_stream_writer writer(static_cast<hexi::pmc::buffer_write&>(buf_ref));
    std::size_t bytes_written = encode_varint(writer, std::uint8_t(127));

    EXPECT_EQ(1, bytes_written);

    hexi::pmc::binary_stream_reader reader(static_cast<hexi::pmc::buffer_read&>(buf_ref));
    std::uint8_t decoded = decode_varint<std::uint8_t>(reader);

    EXPECT_EQ(127, decoded);
}

TEST(Varint, EncodeDecodeMedium) {
    std::vector<std::byte> buffer(1000);
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    hexi::pmc::buffer& buf_ref = adaptor;
    hexi::pmc::binary_stream_writer writer(static_cast<hexi::pmc::buffer_write&>(buf_ref));
    encode_varint(writer, std::uint16_t(128));

    hexi::pmc::binary_stream_reader reader(static_cast<hexi::pmc::buffer_read&>(buf_ref));
    std::uint16_t decoded = decode_varint<std::uint16_t>(reader);

    EXPECT_EQ(128, decoded);
}

