using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Encode using variable-length encoding
    // Each byte uses 7 bits for data and 1 bit (MSB) as continuation flag
    while (value >= 0x80) {
        // Write lower 7 bits with continuation bit set
        std::uint8_t byte = static_cast<std::uint8_t>((value & 0x7F) | 0x80);
        writer << byte;
        value >>= 7;
        bytes_written++;
    }

    // Write final byte (no continuation bit)
    std::uint8_t byte = static_cast<std::uint8_t>(value & 0x7F);
    writer << byte;
    bytes_written++;

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;

    // Decode variable-length encoded integer
    while (true) {
        std::uint8_t byte;
        reader >> byte;

        // Extract lower 7 bits and add to result
        result |= static_cast<T>(byte & 0x7F) << shift;

        // If continuation bit is not set, we're done
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer and adaptor for encoding
    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_adaptor write_adaptor(buffer);

    // Encode the value
    hexi::pmc::binary_stream_writer writer(write_adaptor);
    encode_varint(writer, original_value);

    // Create a new adaptor for reading (buffer now contains encoded data)
    hexi::pmc::buffer_adaptor read_adaptor(buffer);
    hexi::pmc::binary_stream_reader reader(read_adaptor);

    // Decode the value
    T decoded_value = decode_varint<T>(reader);

    // Verify roundtrip correctness
    return decoded_value == original_value;
}
