    std::vector<uint8_t> chunk1 = {1, 2, 3};
    adaptor.write(chunk1.data(), chunk1.size());

    std::size_t free_after_first = adaptor.buffer_write_adaptor<std::vector<uint8_t>>::free();
    EXPECT_EQ(0, free_after_first); // For std::vector that auto-grows, free() is always 0 after write

    // Write second chunk
