#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        adaptor(sensor_id);

        // Write count of temperatures
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor(count);

        // Convert each temperature to little-endian and write using adaptor
        for (float temp : temperatures) {
            float le_temp = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor(le_temp);
        }

        // Convert pressure to little-endian and write using adaptor
        double le_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor(le_pressure);
    }

    void serialise(auto& adaptor) {
        adaptor(sensor_id);

        // Read count of temperatures
        uint32_t count;
        adaptor(count);

        temperatures.clear();
        temperatures.reserve(count);

        // Read each temperature and convert from little-endian to native in-place
        for (uint32_t i = 0; i < count; ++i) {
            float temp;
            adaptor & temp;
            hexi::endian::little_to_native_inplace(temp);
            temperatures.push_back(temp);
        }

        // Read pressure and convert from little-endian to native in-place
        adaptor & pressure;
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    MeasurementData data;
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    SensorInfo info;

    // Read sensor_id (operator>> automatically checks bounds)
    stream >> info.sensor_id;

    // Try to extract sensor name if present (null-terminated string)
    // Note: This assumes sensor name might be present after sensor_id
    // In a real scenario, you'd need to know the format
    // For this example, we'll skip to the end
    if (stream.size() > stream.total_read()) {
        size_t remaining = stream.size() - stream.total_read();
        stream.skip(remaining);
    }

    info.sensor_name = std::string_view{}; // Empty for this example

    return info;
}

