struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Write the number of temperatures
        uint32_t temp_count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(temp_count);

        // Convert and write each temperature to little-endian using conditional_reverse
        for (const auto& temp : temperatures) {
            float converted_temp = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(converted_temp);
        }

        // Convert and write pressure to little-endian using conditional_reverse
        double converted_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read the number of temperatures
        uint32_t temp_count;
        adaptor.read(temp_count);
        temperatures.resize(temp_count);

        // Read and convert each temperature from little-endian to native
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure from little-endian to native
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);
    return buffer;
}

